example_output:
# Valid POST:
POST /api/orders {"symbol":"TCS","quantity":10,"price":3890,"orderType":"BUY","userId":"U01"}
→ 201 {"id":"ORD-001","symbol":"TCS","status":"PENDING",...}

# Blank symbol:
POST /api/orders {"symbol":"","quantity":10,...}
→ 400 {"symbol":"Symbol is required"}

# Invalid pattern:
POST /api/orders {"symbol":"tcs-123",...}
→ 400 {"symbol":"Symbol must be 2-10 uppercase letters"}

# Not found:
GET /api/orders/ORD-999
→ 404 {"status":404,"error":"Not Found","message":"Order ORD-999 not found","path":"/api/orders/ORD-999","timestamp":"..."}

# Insufficient funds:
POST /api/orders {valid data but user has insufficient balance}
→ 422 {"status":422,"error":"Unprocessable Entity","message":"Insufficient funds: need ₹38900, have ₹10000"}
